1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const BLOCK_OF_3_PRICE = 60;
9	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
10	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	export function processScenario(scenario: any): any {
22	  const results: any[] = [];
23	  let quoteCount = 0;
24	  for (const step of scenario.steps) {
25	    let basePremium = 0;
26	    let curseSurcharge = 0;
27	    let highEnchantmentSurcharge = 0;
28	    const typeCounts: Record<string, number> = {};
29	    for (const item of step.items) {
30	      typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
31	      if (item.cursed) {
32	        curseSurcharge += BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE;
33	      }
34	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
35	        highEnchantmentSurcharge += BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
36	      }
37	    }
38	    for (const [type, count] of Object.entries(typeCounts)) {
39	      const isComponentType = COMPONENT_TYPES.has(type);
40	      const formsBlockOf3 = count === 3 && isComponentType;
41	      if (formsBlockOf3) {
42	        basePremium += BLOCK_OF_3_PRICE;
43	      } else {
44	        basePremium += count * BASE_PREMIUM[type];
45	      }
46	    }
47	    let loyaltyDiscount = 0;
48	    if (scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
49	      loyaltyDiscount = basePremium * LOYALTY_DISCOUNT_RATE;
50	    }
51	    const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
52	    let followUpDiscount = 0;
53	    if (quoteCount > 0) {
54	      followUpDiscount = basePremium * FOLLOW_UP_DISCOUNT_RATE;
55	    }
56	    const premium = Math.ceil(basePremium + curseSurcharge + highEnchantmentSurcharge - loyaltyDiscount + firstInsuranceSurcharge - followUpDiscount + PROCESSING_FEE);
57	    results.push({ premium });
58	    quoteCount++;
59	  }
60	  return { results };
61	}
